export type QuizType = 'fill-blank' | 'multiple-choice' | 'short-answer' | 'kr-to-en' | 'en-to-kr';

export const QUIZ_TYPES: QuizType[] = ['fill-blank', 'multiple-choice', 'short-answer', 'kr-to-en', 'en-to-kr'];

export function getQuizTypeLabel(type: QuizType): string {
  const labels: Record<QuizType, string> = {
    'fill-blank': '빈칸 채우기',
    'multiple-choice': '객관식',
    'short-answer': '주관식',
    'kr-to-en': '한→영 전환',
    'en-to-kr': '영→한 전환',
  };
  return labels[type];
}

export function getQuizTypeIcon(type: QuizType): string {
  const icons: Record<QuizType, string> = {
    'fill-blank': '✏️',
    'multiple-choice': '🔘',
    'short-answer': '📝',
    'kr-to-en': '🇰🇷→🇺🇸',
    'en-to-kr': '🇺🇸→🇰🇷',
  };
  return icons[type];
}
